create table if not exists activists(id integer primary key,name text not null,cik text not null unique,slug text not null unique,active integer default 1,created_at text default current_timestamp);
create table if not exists issuers(id integer primary key,name text not null,cik text unique,ticker text,exchange text,asset_class text,country text,sector text,created_at text default current_timestamp);
create table if not exists filings(id integer primary key,activist_id integer not null,issuer_id integer,accession_number text not null unique,form_type text not null,filing_date text,acceptance_datetime text,report_date text,primary_document text,primary_doc_description text,sec_url text,r2_raw_key text,r2_text_key text,parse_status text default 'pending',error text,created_at text default current_timestamp);
create table if not exists positions(id integer primary key,filing_id integer not null unique,activist_id integer not null,issuer_id integer not null,shares real,percent_owned real,prior_percent_owned real,position_change_pct real,ownership_type text,source_form text,as_of_date text,created_at text default current_timestamp);
create table if not exists activism_events(id integer primary key,filing_id integer not null unique,activist_id integer not null,issuer_id integer,event_type text not null,campaign_type text,severity integer default 0,summary text,item4_text text,demands_json text,score real,status text default 'new',reviewed_at text,created_at text default current_timestamp);
create table if not exists documents(id integer primary key,filing_id integer not null,doc_type text,filename text,description text,sec_url text,r2_key text,extracted_text_key text,created_at text default current_timestamp);
create table if not exists watchlist(id integer primary key,issuer_id integer,ticker text,name text,reason text,priority integer default 0,created_at text default current_timestamp);
create table if not exists notes(id integer primary key,issuer_id integer,event_id integer,note text not null,tags text,created_at text default current_timestamp,updated_at text default current_timestamp);
create table if not exists alerts(id integer primary key,event_id integer not null unique,channel text not null,status text default 'pending',sent_at text,error text,created_at text default current_timestamp);
create table if not exists job_runs(id integer primary key,job_name text not null,status text not null,started_at text,finished_at text,duration_ms integer,rows_processed integer,error text);
create table if not exists errors(id integer primary key,source text,message text,context_json text,created_at text default current_timestamp);
